/**
 * Contains utilities for working with colors in the [View](https://developers.arcgis.com/javascript/latest/references/core/views/View/).
 *
 * @since 4.13
 */
import type Color from "../../Color.js";
import type { BasemapTheme } from "../../smartMapping/symbology/types.js";
import type { MapViewOrSceneView } from "../MapViewOrSceneView.js";

/**
 * Returns the average color of the view's background within the view's [MapView.extent](https://developers.arcgis.com/javascript/latest/references/core/views/MapView/#extent).
 * The view's background
 * includes the non-reference [base layers](https://developers.arcgis.com/javascript/latest/references/core/Basemap/#baseLayers) of the
 * [MapView.map](https://developers.arcgis.com/javascript/latest/references/core/views/MapView/#map)'s basemap, the [background color](https://developers.arcgis.com/javascript/latest/references/core/webmap/InitialViewProperties/#background) of the web map
 * (if applicable), and the background color of the view's [MapView.container](https://developers.arcgis.com/javascript/latest/references/core/views/MapView/#container).
 *
 * @param view - The view instance from which to
 *   calculate the average color of the background.
 * @returns Resolves to the average color of the input view's background.
 * @example
 * viewColorUtils.getBackgroundColor(view)
 *   .then(function(averageColor){
 *     // averageColor is the input view's average background color
 *   });
 */
export function getBackgroundColor(view: MapViewOrSceneView): Promise<Color | null | undefined>;

/**
 * This method inspects the basemap and background of a MapView and returns either
 * `light` or `dark` as the theme of the background depending on if the average
 * color of the basemap and the view's background is light or dark.
 *
 * The background theme is determined by taking the average color of the view's background
 * and basemap and determining its brightness based on [this algorithm for determining color visibility](https://www.w3.org/TR/AERT/#color-contrast).
 *
 * @param view - The MapView instance from which to
 *   get the background color theme.
 * @returns Resolves to a string whose value can be either `light` or `dark`.
 * @example
 * const backgroundTheme = await viewColorUtils.getBackgroundColorTheme(view);
 * if(backgroundTheme === "dark"){
 *   // style other app elements with a dark theme
 * }
 */
export function getBackgroundColorTheme(view: MapViewOrSceneView): Promise<BasemapTheme | null | undefined>;